---战斗日志
---@class LBattleLogicLogMgr
local LBattleLogicLogMgr = classX("LBattleLogicLogMgr",nil)

function LBattleLogicLogMgr:ctor(logicMgr)
    ---@type LBattleLogicMgr
    self._logicMgr = logicMgr

    self._hpRecordList = {}

    self._splitStr = "=======>"

    self._isEnable = ENABLE_FIGHT_LOG
end

function LBattleLogicLogMgr:Dispose()
    table.dispose(self)
end

function LBattleLogicLogMgr:IsLogOpen()
    return self._isEnable
end

function LBattleLogicLogMgr:LogNormal(str)
    if not self:IsLogOpen() then return end
    if LOG_INFO_ENABLED then
        printInfo("battle", tostring(str))
    end
end

function LBattleLogicLogMgr:LogError(str)
    if not self:IsLogOpen() then return end
    if LOG_INFO_ENABLED then
        printError("battle", tostring(str))
    end
end

function LBattleLogicLogMgr:LogHpChange(id,maHp,nowHP,oldHp,changeHp)
    if not self:IsLogOpen() then return end

    table.insert(self._hpRecordList,
            string.format("%s : max=%s , (%s + %s -> %s)",
                    tostring(id),tostring(maHp),tostring(oldHp),tostring(changeHp),tostring(nowHP)
            )
    )
end

function LBattleLogicLogMgr:SaveHpLog()
    if not self:IsLogOpen() then return end
    if (not CS.IsUnityEdit()) then
        return
    end
    local reportData = self._logicMgr:GetReportData()
    local reportId = reportData:GetReportId()

    local filePath = LxPathHelper.AppPersistentDataPath.."/FightLogs/hp_"..reportId..".log"
    local contents = table.concat(self._hpRecordList,"\n")
    CS.FileWriteText(filePath, contents)
end

function LBattleLogicLogMgr:LogHpFinal(formationA,formationB)
    if not self:IsLogOpen() then return end

    table.insert(self._hpRecordList,self._splitStr)
    table.insert(self._hpRecordList,"")
    table.insert(self._hpRecordList,"formationA")
    for k,v in ipairs(formationA) do
        table.insert(self._hpRecordList,v:ToHpString())
    end

    table.insert(self._hpRecordList,"")
    table.insert(self._hpRecordList,"formationB")
    for k,v in ipairs(formationB) do
        table.insert(self._hpRecordList,v:ToHpString())
    end
end

-----------------------------------------------------------------
return LBattleLogicLogMgr